 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { usePendingChanges } from '@kubevirt-utils/components/PendingChanges/hooks/usePendingChanges';
 5	import { PendingChangesAlert } from '@kubevirt-utils/components/PendingChanges/PendingChangesAlert/PendingChangesAlert';
 6	import { getStatusConditionByType } from '@kubevirt-utils/resources/vm';
 7	import { VirtualMachineStatusConditionTypes } from '@kubevirt-utils/resources/vm/utils/constants';
 8	import { isEmpty } from '@kubevirt-utils/utils/utils';
 9	import { Stack, StackItem } from '@patternfly/react-core';
10	import LiveMigratePendingChanges from '@virtualmachines/details/VirtualMachinePendingChangesAlert/LiveMigratePendingChanges';
11	import RestartPendingChanges from '@virtualmachines/details/VirtualMachinePendingChangesAlert/RestartPendingChanges';
12	import { isRunning } from '@virtualmachines/utils';
13	
14	import { splitPendingChanges } from '../utils/utils';
15	
16	type VirtualMachinePendingChangesAlertProps = {
17	  vm: V1VirtualMachine;
18	  vmi: V1VirtualMachineInstance;
19	};
20	
21	const VirtualMachinePendingChangesAlert: FC<VirtualMachinePendingChangesAlertProps> = ({
22	  vm,
23	  vmi,
24	}) => {
25	  const pendingChanges = usePendingChanges(vm, vmi);
26	
27	  const hasPendingChanges = pendingChanges?.some((change) => change?.hasPendingChange);
28	
29	  if (!vmi || !isRunning(vm) || !hasPendingChanges) {
30	    return null;
31	  }
32	
33	  const { liveMigrationChanges, restartChanges } = splitPendingChanges(pendingChanges);
34	  const restartRequiredCondition = getStatusConditionByType(
35	    vm,
36	    VirtualMachineStatusConditionTypes.RestartRequired,
37	  );
38	
39	  return (
40	    <PendingChangesAlert isExpandable isWarning>
41	      <Stack hasGutter>
42	        {!isEmpty(liveMigrationChanges) && (
43	          <StackItem>
44	            <LiveMigratePendingChanges pendingChanges={liveMigrationChanges} />
45	          </StackItem>
46	        )}
47	        {!isEmpty(restartChanges) && (
48	          <StackItem>
49	            <RestartPendingChanges
50	              pendingChanges={restartChanges}
51	              restartRequiredCondition={restartRequiredCondition}
52	            />
53	          </StackItem>
54	        )}
55	      </Stack>
56	    </PendingChangesAlert>
57	  );
58	};
59	
60	export default VirtualMachinePendingChangesAlert;

